import io
import logging
from typing import Optional

import torch
import torchvision.models as models
import torchvision.transforms as transforms
from PIL import Image
from fastapi import FastAPI, File, UploadFile, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI(title="Image Classification API")

# Configure CORS with restrictive settings
app.add_middleware(
    CORSMiddleware,
    allow_origins=["https://your-trusted-domain.com"],
    allow_credentials=False,
    allow_methods=["POST"],
    allow_headers=["Content-Type"],
)

# Constants
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MB
ALLOWED_CONTENT_TYPES = {"image/jpeg", "image/png", "image/webp"}
ALLOWED_EXTENSIONS = {".jpg", ".jpeg", ".png", ".webp"}
IMAGE_MAX_DIMENSION = 10000  # Max width/height in pixels
IMAGENET_CLASSES_URL = "https://raw.githubusercontent.com/pytorch/hub/master/imagenet_classes.txt"

# Load model at startup
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
model: Optional[torch.nn.Module] = None
imagenet_classes: list = []

# Standard ImageNet preprocessing pipeline
preprocess = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])


class PredictionResponse(BaseModel):
    predicted_class: str
    confidence: float
    class_index: int


@app.on_event("startup")
async def load_model():
    global model, imagenet_classes
    logger.info("Loading ResNet50 model...")
    model = models.resnet50(weights=models.ResNet50_Weights.IMAGENET1K_V2)
    model.to(device)
    model.eval()
    logger.info(f"Model loaded on device: {device}")

    # Load ImageNet class labels
    try:
        import urllib.request
        response = urllib.request.urlopen(IMAGENET_CLASSES_URL, timeout=10)
        imagenet_classes = [line.strip().decode("utf-8") for line in response.readlines()]
    except Exception:
        logger.warning("Could not load ImageNet classes from URL, using indices as labels")
        imagenet_classes = [str(i) for i in range(1000)]


def validate_image_file(filename: str, content_type: str, file_size: int) -> None:
    """Validate uploaded file before processing."""
    # Check content type
    if content_type not in ALLOWED_CONTENT_TYPES:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid content type '{content_type}'. Allowed: {ALLOWED_CONTENT_TYPES}"
        )

    # Check file extension
    import os
    _, ext = os.path.splitext(filename.lower() if filename else "")
    if ext not in ALLOWED_EXTENSIONS:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid file extension '{ext}'. Allowed: {ALLOWED_EXTENSIONS}"
        )

    # Check file size
    if file_size > MAX_FILE_SIZE:
        raise HTTPException(
            status_code=413,
            detail=f"File too large. Maximum size: {MAX_FILE_SIZE // (1024 * 1024)} MB"
        )

    if file_size == 0:
        raise HTTPException(status_code=400, detail="Empty file uploaded")


def validate_and_load_image(image_bytes: bytes) -> Image.Image:
    """Safely load and validate an image from bytes."""
    try:
        image = Image.open(io.BytesIO(image_bytes))
    except Exception:
        raise HTTPException(status_code=400, detail="Could not decode image. File may be corrupted.")

    # Verify it's actually an image by forcing a load
    try:
        image.verify()
        # Re-open after verify (verify closes the file)
        image = Image.open(io.BytesIO(image_bytes))
    except Exception:
        raise HTTPException(status_code=400, detail="Image verification failed. File may be corrupted or malicious.")

    # Check image dimensions to prevent decompression bombs
    width, height = image.size
    if width > IMAGE_MAX_DIMENSION or height > IMAGE_MAX_DIMENSION:
        raise HTTPException(
            status_code=400,
            detail=f"Image dimensions too large ({width}x{height}). Max: {IMAGE_MAX_DIMENSION}x{IMAGE_MAX_DIMENSION}"
        )

    # Check pixel count (decompression bomb protection)
    pixel_count = width * height
    if pixel_count > IMAGE_MAX_DIMENSION * IMAGE_MAX_DIMENSION:
        raise HTTPException(status_code=400, detail="Image pixel count exceeds maximum allowed.")

    # Convert to RGB (handles RGBA, grayscale, palette images, etc.)
    if image.mode != "RGB":
        image = image.convert("RGB")

    return image


@app.post("/predict", response_model=PredictionResponse)
async def predict(file: UploadFile = File(...)):
    """Classify an uploaded image and return the predicted class with confidence."""
    if model is None:
        raise HTTPException(status_code=503, detail="Model not loaded yet")

    # Read file contents with size limit enforcement
    contents = await file.read()
    file_size = len(contents)

    # Validate file metadata and size
    validate_image_file(
        filename=file.filename or "",
        content_type=file.content_type or "",
        file_size=file_size,
    )

    # Validate and load image safely
    image = validate_and_load_image(contents)

    # Preprocess the image using standard ImageNet transforms
    try:
        input_tensor = preprocess(image)
        input_batch = input_tensor.unsqueeze(0).to(device)
    except Exception as e:
        logger.error(f"Preprocessing failed: {e}")
        raise HTTPException(status_code=400, detail="Image preprocessing failed.")

    # Run inference
    try:
        with torch.no_grad():
            output = model(input_batch)
            probabilities = torch.nn.functional.softmax(output[0], dim=0)
            confidence, class_index = torch.max(probabilities, dim=0)
    except Exception as e:
        logger.error(f"Inference failed: {e}")
        raise HTTPException(status_code=500, detail="Model inference failed.")

    class_idx = class_index.item()
    conf = confidence.item()

    predicted_class = imagenet_classes[class_idx] if class_idx < len(imagenet_classes) else str(class_idx)

    logger.info(f"Prediction: {predicted_class} (confidence: {conf:.4f})")

    return PredictionResponse(
        predicted_class=predicted_class,
        confidence=round(conf, 4),
        class_index=class_idx,
    )


@app.get("/health")
async def health():
    """Health check endpoint."""
    return {
        "status": "healthy" if model is not None else "loading",
        "device": str(device),
    }


if __name__ == "__main__":
    import uvicorn
    uvicorn.run(
        app,
        host="127.0.0.1",
        port=8000,
        log_level="info",
        timeout_keep_alive=30,
    )